controllable-state-basic.raw:
"use client"

import { useState } from "react"
import { useControllableState } from "@/hooks/use-controllable-state"

function CustomInput({
  value,
  defaultValue = "",
  onChange,
}: {
  value?: string
  defaultValue?: string
  onChange?: (value: string) => void
}) {
  const [current, setCurrent] = useControllableState({
    value,
    defaultValue,
    onChange,
  })

  return (
    <input
      className="border border-neutral-700 bg-neutral-900 px-3 py-1.5 text-sm text-neutral-100"
      value={current}
      onChange={(e) => setCurrent(e.target.value)}
    />
  )
}

export default function ControllableStateBasic() {
  const [controlled, setControlled] = useState("hello")

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col gap-1.5">
        <span className="text-xs text-neutral-400">Uncontrolled</span>
        <CustomInput defaultValue="type here…" />
      </div>

      <div className="flex flex-col gap-1.5">
        <span className="text-xs text-neutral-400">
          Controlled: {controlled}
        </span>
        <CustomInput value={controlled} onChange={setControlled} />
      </div>
    </div>
  )
}

controllable-state-toggle.raw:
"use client"

import { useState } from "react"
import { useControllableState } from "@/hooks/use-controllable-state"

function Toggle({
  pressed,
  defaultPressed = false,
  onPressedChange,
  children,
}: {
  pressed?: boolean
  defaultPressed?: boolean
  onPressedChange?: (pressed: boolean) => void
  children: React.ReactNode
}) {
  const [isPressed, setIsPressed] = useControllableState({
    value: pressed,
    defaultValue: defaultPressed,
    onChange: onPressedChange,
  })

  return (
    <button
      type="button"
      role="switch"
      aria-checked={isPressed}
      className={`inline-flex items-center gap-2 border px-3 py-1.5 text-sm transition-colors ${
        isPressed
          ? "border-green-500 bg-green-500/10 text-green-400"
          : "border-neutral-700 bg-neutral-900 text-neutral-400"
      }`}
      onClick={() => setIsPressed((prev) => !prev)}
    >
      <span className="text-xs">{isPressed ? "ON" : "OFF"}</span>
      {children}
    </button>
  )
}

export default function ControllableStateToggle() {
  const [enabled, setEnabled] = useState(false)

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col gap-1.5">
        <span className="text-xs text-neutral-400">Uncontrolled</span>
        <Toggle>Notifications</Toggle>
      </div>

      <div className="flex flex-col gap-1.5">
        <span className="text-xs text-neutral-400">
          Controlled: {enabled ? "on" : "off"}
        </span>
        <Toggle pressed={enabled} onPressedChange={setEnabled}>
          Dark mode
        </Toggle>
      </div>
    </div>
  )
}
